In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions. You can also use the `dup2()` function to redirect file descriptors. Below is an example that demonstrates how to achieve this:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <fcntl.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <cstdio>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid == -1) {
        perror("fork");
        return 1;
    }

    if (pid == 0) { // Child process
        // Close unused read end of pipe
        close(pipefd[0]);

        // Duplicate the pipe's write end to stdout
        dup2(pipefd[1], STDOUT_FILENO);

        // Close the write end of the pipe
        close(pipefd[1]);

        // Execute the command
        execlp("ls", "ls", NULL);
        perror("execlp");
        _exit(1);
    } else { // Parent process
        // Close unused write end of pipe
        close(pipefd[1]);

        // Read from the pipe
        char buffer[1024];
        ssize_t bytes_read = read(pipefd[0], buffer, sizeof(buffer) - 1);
        if (bytes_read > 0) {
            buffer[bytes_read] = '\0'; // Null-terminate the string
            std::cout << "Output from the child process: " << buffer << std::endl;
        }

        // Wait for the child to finish
        wait(NULL);

        // Close the read end of the pipe
        close(pipefd[0]);
    }

    return 0;
}
